args.query:
WITH etfs AS (
  SELECT Symbol
  FROM read_csv_auto('stockinfo_database/stockinfo.csv', header=true)
  WHERE "Listing Exchange" = 'P' AND ETF = 'Y'
), candidate_tables AS (
  SELECT t.table_name AS Symbol
  FROM information_schema.tables t
  JOIN etfs e ON e.Symbol = t.table_name
), unioned AS (
  SELECT * FROM (
    SELECT Symbol FROM candidate_tables
  )
)
SELECT 1;

